// Auto-migrated from the original static guide HTML. Structural markup
// and code samples are preserved; inline styles, scripts, and the guide's
// own bespoke syntax-highlight token classes were stripped so every guide
// renders through the one shared GuideReader stylesheet.
export const html: string = "<section class=\"step\" id=\"s1\">\n<div class=\"step-header\">\n<div class=\"step-badge\">01</div>\n<h2>Prerequisites</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A user management system touches auth flows, emails, a database, and role logic. Confirming the toolchain before you start means you won't debug three missing packages at once mid-build.</div>\n<div class=\"step-body\">\n<p>You need Python 3.10+, pip, and PostgreSQL. SQLite is fine for local dev but you'll switch to Postgres before deploying, so install it now.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>python3 --version <span># 3.10 or newer</span>\npip3 --version\npsql --version <span># PostgreSQL client</span>\ngit --version <span># version control</span></pre>\n</div>\n<div>No Node.js required \u2014 all CSS and JS in this guide is hand-written and served by Django's static file system. Add a build step later if you want Tailwind.</div>\n<div class=\"stat-grid\">\n<div class=\"stat-card\">\n<div class=\"stat-label\">Python min.</div>\n<div class=\"stat-value\">3.10</div>\n<div class=\"stat-sub\">+ recommended</div>\n</div>\n<div class=\"stat-card\">\n<div class=\"stat-label\">Django</div>\n<div class=\"stat-value\">5.x</div>\n<div class=\"stat-sub\">latest stable</div>\n</div>\n<div class=\"stat-card\">\n<div class=\"stat-label\">Database</div>\n<div class=\"stat-value\">PG 15</div>\n<div class=\"stat-sub\">PostgreSQL</div>\n</div>\n<div class=\"stat-card\">\n<div class=\"stat-label\">Deploy</div>\n<div class=\"stat-value\">~30m</div>\n<div class=\"stat-sub\">Railway / Render</div>\n</div>\n</div>\n</section>\n<section class=\"step\" id=\"s2\">\n<div class=\"step-header\">\n<div class=\"step-badge\">02</div>\n<h2>Create a virtual environment</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Isolating dependencies per project means upgrading Django for one project never breaks another, and <code>requirements.txt</code> stays a trustworthy, reproducible list.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">your project root</span>\n</div>\n<pre>mkdir usermgmt &amp;&amp; cd usermgmt\npython3 -m venv venv\nsource venv/bin/activate <span># macOS / Linux</span>\n# venv\\Scripts\\activate <span># Windows PowerShell</span></pre>\n</div>\n<div>Your prompt will show <code>(venv)</code> once active. Run <code>deactivate</code> to leave it. Never commit the <code>venv/</code> folder \u2014 add it to <code>.gitignore</code> in Step 5.</div>\n</section>\n<section class=\"step\" id=\"s3\">\n<div class=\"step-header\">\n<div class=\"step-badge\">03</div>\n<h2>Install dependencies</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Installing the full stack up front \u2014 Django, Postgres driver, email, and auth helpers \u2014 means you won't hit a missing-package error halfway through building a feature.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install django psycopg2-binary python-decouple \\\n gunicorn whitenoise pillow django-extensions\npip freeze &gt; requirements.txt\npython -m django --version <span># should print 5.x</span></pre>\n</div>\n<div class=\"table-wrap\">\n<table>\n<tr><th>Package</th><th>Purpose</th></tr>\n<tr><td><code>django</code></td><td>The web framework itself</td></tr>\n<tr><td><code>psycopg2-binary</code></td><td>PostgreSQL driver</td></tr>\n<tr><td><code>python-decouple</code></td><td>Reads secrets from <code>.env</code> file</td></tr>\n<tr><td><code>gunicorn</code></td><td>Production WSGI server</td></tr>\n<tr><td><code>whitenoise</code></td><td>Serves static files in production without Nginx</td></tr>\n<tr><td><code>pillow</code></td><td>Image processing for user avatars</td></tr>\n<tr><td><code>django-extensions</code></td><td>Useful management commands for dev (<code>shell_plus</code>, etc.)</td></tr>\n</table>\n</div>\n</section>\n<section class=\"step\" id=\"s4\">\n<div class=\"step-header\">\n<div class=\"step-badge\">04</div>\n<h2>Create the project and apps</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>The user management system splits cleanly into two concerns: <strong>accounts</strong> (auth, profiles, roles) and <strong>dashboard</strong> (analytics, tables, admin UI). Keeping them separate now means role logic never leaks into display code.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">inside usermgmt/</span>\n</div>\n<pre>django-admin startproject core .\npython manage.py startapp accounts\npython manage.py startapp dashboard</pre>\n</div>\n<div>\n<div class=\"arch-box\">Browser</div>\n<div class=\"arch-arrow\">\u2192</div>\n<div class=\"arch-box\">core/urls.py</div>\n<div class=\"arch-arrow\">\u2192</div>\n<div class=\"arch-box\">accounts/</div>\n<div class=\"arch-arrow\">+</div>\n<div class=\"arch-box\">dashboard/</div>\n<div class=\"arch-arrow\">\u2192</div>\n<div class=\"arch-box\">PostgreSQL</div>\n</div>\n<div><strong>accounts</strong> owns User model, signup/login, password reset, email verification, and roles. <strong>dashboard</strong> owns the admin UI \u2014 user lists, charts, activity logs, and profile editing.</div>\n</section>\n<section class=\"step\" id=\"s5\">\n<div class=\"step-header\">\n<div class=\"step-badge\">05</div>\n<h2>Project structure</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Knowing exactly where templates, static files, and settings live prevents the most common beginner mistake: editing a file Django isn't actually loading.</div>\n<div>\n\n<div class=\"tree\" id=\"tree-s5\">\n<span>usermgmt/</span>\n \u251c\u2500\u2500 <span>core/</span> <span># project package</span>\n \u2502 \u251c\u2500\u2500 <span>settings/</span> <span># split settings (Step 6)</span>\n \u2502 \u2502 \u251c\u2500\u2500 <span>__init__.py</span>\n \u2502 \u2502 \u251c\u2500\u2500 <span>base.py</span>\n \u2502 \u2502 \u251c\u2500\u2500 <span>dev.py</span>\n \u2502 \u2502 \u2514\u2500\u2500 <span>prod.py</span>\n \u2502 \u251c\u2500\u2500 <span>urls.py</span>\n \u2502 \u2514\u2500\u2500 <span>wsgi.py</span>\n \u251c\u2500\u2500 <span>accounts/</span> <span># auth, profiles, roles</span>\n \u2502 \u251c\u2500\u2500 <span>models.py</span> <span># CustomUser, Role, Permission</span>\n \u2502 \u251c\u2500\u2500 <span>views.py</span>\n \u2502 \u251c\u2500\u2500 <span>forms.py</span>\n \u2502 \u251c\u2500\u2500 <span>urls.py</span>\n \u2502 \u251c\u2500\u2500 <span>signals.py</span> <span># send welcome email on register</span>\n \u2502 \u2514\u2500\u2500 <span>admin.py</span>\n \u251c\u2500\u2500 <span>dashboard/</span> <span># admin UI screens</span>\n \u2502 \u251c\u2500\u2500 <span>views.py</span> <span># user list, charts, activity</span>\n \u2502 \u251c\u2500\u2500 <span>urls.py</span>\n \u2502 \u2514\u2500\u2500 <span>templatetags/</span>\n \u251c\u2500\u2500 <span>templates/</span> <span># project-level templates</span>\n \u2502 \u251c\u2500\u2500 <span>base.html</span>\n \u2502 \u251c\u2500\u2500 <span>accounts/</span>\n \u2502 \u2514\u2500\u2500 <span>dashboard/</span>\n \u251c\u2500\u2500 <span>static/</span>\n \u2502 \u251c\u2500\u2500 <span>css/</span>\n \u2502 \u2514\u2500\u2500 <span>js/</span>\n \u251c\u2500\u2500 <span>media/</span> <span># user uploads (avatars)</span>\n \u251c\u2500\u2500 <span>.env</span> <span># never commit</span>\n \u251c\u2500\u2500 <span>.gitignore</span>\n \u251c\u2500\u2500 <span>manage.py</span>\n \u2514\u2500\u2500 <span>requirements.txt</span>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">.gitignore</span>\n</div>\n<pre>venv/\n.env\n__pycache__/\n*.pyc\ndb.sqlite3\nstaticfiles/\nmedia/\n.DS_Store</pre>\n</div>\n<div class=\"tone-danger\"><strong>Watch out:</strong> <code>.env</code> holds your secret key, database credentials, and email SMTP password. If it ever gets committed, rotate every credential immediately \u2014 don't just delete the commit.</div>\n</section>\n<section class=\"step\" id=\"s6\">\n<div class=\"step-header\">\n<div class=\"step-badge\">06</div>\n<h2>Split settings into base / dev / prod</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A single <code>settings.py</code> tempts you to hardcode <code>DEBUG = True</code> and ship it. Splitting settings by environment makes \"which config am I running\" an explicit, auditable choice.</div>\n<div class=\"step-body\">\n<p>Delete the generated <code>core/settings.py</code> and replace it with a <code>core/settings/</code> package.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>rm core/settings.py\nmkdir core/settings\ntouch core/settings/__init__.py core/settings/base.py \\\n core/settings/dev.py core/settings/prod.py</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/base.py</span>\n</div>\n<pre><span>from</span> pathlib <span>import</span> Path\n<span>from</span> decouple <span>import</span> config\n\nBASE_DIR = Path(__file__).resolve().parent.parent.parent\n\nSECRET_KEY = config(<span>'SECRET_KEY'</span>)\nALLOWED_HOSTS = []\n\nINSTALLED_APPS = [\n <span>'django.contrib.admin'</span>,\n <span>'django.contrib.auth'</span>,\n <span>'django.contrib.contenttypes'</span>,\n <span>'django.contrib.sessions'</span>,\n <span>'django.contrib.messages'</span>,\n <span>'django.contrib.staticfiles'</span>,\n <span>'accounts'</span>,\n <span>'dashboard'</span>,\n <span>'django_extensions'</span>,\n]\n\nAUTH_USER_MODEL = <span>'accounts.CustomUser'</span>\nLOGIN_REDIRECT_URL = <span>'/dashboard/'</span>\nLOGOUT_REDIRECT_URL = <span>'/accounts/login/'</span>\nLOGIN_URL = <span>'/accounts/login/'</span>\n\nTEMPLATES = [{\n <span>'BACKEND'</span>: <span>'django.template.backends.django.DjangoTemplates'</span>,\n <span>'DIRS'</span>: [BASE_DIR / <span>'templates'</span>],\n <span>'APP_DIRS'</span>: <span>True</span>,\n <span>'OPTIONS'</span>: {<span>'context_processors'</span>: [\n <span>'django.template.context_processors.debug'</span>,\n <span>'django.template.context_processors.request'</span>,\n <span>'django.contrib.auth.context_processors.auth'</span>,\n <span>'django.contrib.messages.context_processors.messages'</span>,\n ]},\n}]\n\nSTATIC_URL = <span>'/static/'</span>\nSTATICFILES_DIRS = [BASE_DIR / <span>'static'</span>]\nSTATIC_ROOT = BASE_DIR / <span>'staticfiles'</span>\nMEDIA_URL = <span>'/media/'</span>\nMEDIA_ROOT = BASE_DIR / <span>'media'</span>\n\nDEFAULT_AUTO_FIELD = <span>'django.db.models.BigAutoField'</span>\n\n<span># Email (override in dev.py / prod.py)</span>\nEMAIL_BACKEND = <span>'django.core.mail.backends.console.EmailBackend'</span>\nDEFAULT_FROM_EMAIL = config(<span>'DEFAULT_FROM_EMAIL'</span>, default=<span>'noreply@example.com'</span>)</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/dev.py</span>\n</div>\n<pre><span>from</span> .base <span>import</span> *\n\nDEBUG = <span>True</span>\nALLOWED_HOSTS = [<span>'*'</span>]\n\nDATABASES = {<span>'default'</span>: {\n <span>'ENGINE'</span>: <span>'django.db.backends.sqlite3'</span>,\n <span>'NAME'</span>: BASE_DIR / <span>'db.sqlite3'</span>,\n}}</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">.env</span>\n</div>\n<pre>SECRET_KEY=replace-me-with-a-50-char-random-string\nDJANGO_SETTINGS_MODULE=core.settings.dev\nDATABASE_URL=postgres://user:pass@localhost/usermgmt\nDEFAULT_FROM_EMAIL=noreply@yourdomain.com\nEMAIL_HOST=smtp.gmail.com\nEMAIL_PORT=587\nEMAIL_HOST_USER=you@gmail.com\nEMAIL_HOST_PASSWORD=your-app-password</pre>\n</div>\n</section>\n<section class=\"step\" id=\"s7\">\n<div class=\"step-header\">\n<div class=\"step-badge\">07</div>\n<h2>Custom User model</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django's built-in User model cannot be easily extended after migrations have run. Defining <code>AUTH_USER_MODEL</code> <em>before the first migration</em> is the single most important architectural decision in this guide \u2014 it cannot be undone cheaply.</div>\n<div class=\"step-body\">\n<p>Add avatar, bio, phone, and a <code>role</code> FK to your custom user. The model also tracks email verification state and last login IP.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/models.py</span>\n</div>\n<pre><span>from</span> django.contrib.auth.models <span>import</span> AbstractUser\n<span>from</span> django.db <span>import</span> models\n\n\n<span>class</span> <span>Role</span>(models.Model):\n name = models.CharField(max_length=<span>64</span>, unique=<span>True</span>)\n description = models.TextField(blank=<span>True</span>)\n created_at = models.DateTimeField(auto_now_add=<span>True</span>)\n\n <span>def</span> <span>__str__</span>(<span>self</span>):\n <span>return</span> <span>self</span>.name\n\n <span>class</span> <span>Meta</span>:\n ordering = [<span>'name'</span>]\n\n\n<span>class</span> <span>CustomUser</span>(AbstractUser):\n <span># Extra profile fields</span>\n avatar = models.ImageField(upload_to=<span>'avatars/'</span>, blank=<span>True</span>, null=<span>True</span>)\n bio = models.TextField(blank=<span>True</span>)\n phone = models.CharField(max_length=<span>20</span>, blank=<span>True</span>)\n role = models.ForeignKey(\n Role, on_delete=models.SET_NULL,\n null=<span>True</span>, blank=<span>True</span>, related_name=<span>'users'</span>\n )\n\n <span># Verification &amp; security</span>\n email_verified = models.BooleanField(default=<span>False</span>)\n verify_token = models.CharField(max_length=<span>64</span>, blank=<span>True</span>)\n last_login_ip = models.GenericIPAddressField(null=<span>True</span>, blank=<span>True</span>)\n\n <span>def</span> <span>__str__</span>(<span>self</span>):\n <span>return</span> <span>self</span>.email\n\n <span>def</span> <span>full_name</span>(<span>self</span>):\n <span>return</span> <span>f\"</span>{<span>self</span>.first_name} {<span>self</span>.last_name}<span>\"</span>.strip() <span>or</span> <span>self</span>.username\n\n\n<span>class</span> <span>ActivityLog</span>(models.Model):\n user = models.ForeignKey(CustomUser, on_delete=models.CASCADE,\n related_name=<span>'activity_logs'</span>)\n action = models.CharField(max_length=<span>255</span>)\n ip_address = models.GenericIPAddressField(null=<span>True</span>, blank=<span>True</span>)\n created_at = models.DateTimeField(auto_now_add=<span>True</span>)\n\n <span>class</span> <span>Meta</span>:\n ordering = [<span>'-created_at'</span>]</pre>\n</div>\n<div class=\"tone-tip\"><strong>Critical:</strong> Add <code>AUTH_USER_MODEL = 'accounts.CustomUser'</code> to <code>base.py</code> <strong>before</strong> running any migration. Changing this after the first <code>migrate</code> requires deleting your database and starting over.</div>\n</section>\n<section class=\"step\" id=\"s8\">\n<div class=\"step-header\">\n<div class=\"step-badge\">08</div>\n<h2>Role &amp; Permission model</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django's built-in permission system is granular but verbose. Adding a lightweight <code>Role</code> model (admin, staff, viewer) gives you coarse-grained access control that's easy to check in views and templates, without replacing Django's own permissions.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/models.py (append)</span>\n</div>\n<pre><span>class</span> <span>RoleChoices</span>(models.TextChoices):\n ADMIN = <span>'admin'</span>, <span>'Administrator'</span>\n STAFF = <span>'staff'</span>, <span>'Staff'</span>\n VIEWER = <span>'viewer'</span>, <span>'Viewer'</span></pre>\n</div>\n<div class=\"step-body\">\n<p>Then add a <code>role_name</code> field directly to the User or use the <code>Role</code> FK already defined. For most apps, a simple <code>role_name = CharField(choices=RoleChoices.choices)</code> field is sufficient and avoids a join on every permission check.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/models.py \u2014 simplified pattern</span>\n</div>\n<pre><span>class</span> <span>CustomUser</span>(AbstractUser):\n role_name = models.CharField(\n max_length=<span>16</span>,\n choices=RoleChoices.choices,\n default=RoleChoices.VIEWER,\n )\n <span># ... other fields ...</span>\n\n <span>@property</span>\n <span>def</span> <span>is_admin_user</span>(<span>self</span>):\n <span>return</span> <span>self</span>.role_name == RoleChoices.ADMIN\n\n <span>@property</span>\n <span>def</span> <span>is_staff_user</span>(<span>self</span>):\n <span>return</span> <span>self</span>.role_name <span>in</span> (RoleChoices.ADMIN, RoleChoices.STAFF)</pre>\n</div>\n<div class=\"table-wrap\">\n<table>\n<tr><th>Role</th><th>Can see user list</th><th>Can edit users</th><th>Can delete users</th><th>Can manage roles</th></tr>\n<tr><td><code>admin</code></td><td></td><td></td><td></td><td></td></tr>\n<tr><td><code>staff</code></td><td></td><td></td><td>\u2014</td><td>\u2014</td></tr>\n<tr><td><code>viewer</code></td><td></td><td>\u2014</td><td>\u2014</td><td>\u2014</td></tr>\n</table>\n</div>\n</section>\n<section class=\"step\" id=\"s9\">\n<div class=\"step-header\">\n<div class=\"step-badge\">09</div>\n<h2>Run migrations &amp; create superuser</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Migrations translate your Python model definitions into actual database tables. Because you defined the custom User model first, Django will build the whole auth system on top of it.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>python manage.py makemigrations accounts\npython manage.py makemigrations\npython manage.py migrate\npython manage.py createsuperuser</pre>\n</div>\n<div>After <code>createsuperuser</code>, log into <code>/admin/</code> to confirm Django's admin works with your custom user model. You should see the <code>CustomUser</code> table listed under <strong>Accounts</strong>.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/admin.py</span>\n</div>\n<pre><span>from</span> django.contrib <span>import</span> admin\n<span>from</span> django.contrib.auth.admin <span>import</span> UserAdmin\n<span>from</span> .models <span>import</span> CustomUser, ActivityLog\n\n<span>@admin.register</span>(CustomUser)\n<span>class</span> <span>CustomUserAdmin</span>(UserAdmin):\n list_display = (<span>'email'</span>, <span>'username'</span>, <span>'role_name'</span>, <span>'email_verified'</span>, <span>'is_active'</span>)\n list_filter = (<span>'role_name'</span>, <span>'is_active'</span>, <span>'email_verified'</span>)\n search_fields = (<span>'email'</span>, <span>'username'</span>, <span>'first_name'</span>, <span>'last_name'</span>)\n fieldsets = UserAdmin.fieldsets + (\n (<span>'Profile'</span>, {<span>'fields'</span>: (<span>'avatar'</span>, <span>'bio'</span>, <span>'phone'</span>, <span>'role_name'</span>)}),\n (<span>'Verification'</span>, {<span>'fields'</span>: (<span>'email_verified'</span>, <span>'verify_token'</span>)}),\n )\n\n<span>@admin.register</span>(ActivityLog)\n<span>class</span> <span>ActivityLogAdmin</span>(admin.ModelAdmin):\n list_display = (<span>'user'</span>, <span>'action'</span>, <span>'ip_address'</span>, <span>'created_at'</span>)\n list_filter = (<span>'created_at'</span>,)\n search_fields = (<span>'user__email'</span>, <span>'action'</span>)</pre>\n</div>\n</section>\n<section class=\"step\" id=\"s10\">\n<div class=\"step-header\">\n<div class=\"step-badge\">10</div>\n<h2>Registration &amp; login views</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django ships with login/logout views but not a registration view. You need a custom signup form that collects email (not just username), assigns a default role, and triggers the email verification flow.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/forms.py</span>\n</div>\n<pre><span>from</span> django <span>import</span> forms\n<span>from</span> django.contrib.auth.forms <span>import</span> UserCreationForm\n<span>from</span> .models <span>import</span> CustomUser\n\n<span>class</span> <span>SignupForm</span>(UserCreationForm):\n email = forms.EmailField(required=<span>True</span>)\n first_name = forms.CharField(max_length=<span>50</span>)\n last_name = forms.CharField(max_length=<span>50</span>)\n\n <span>class</span> <span>Meta</span>:\n model = CustomUser\n fields = (<span>'username'</span>, <span>'email'</span>, <span>'first_name'</span>,\n <span>'last_name'</span>, <span>'password1'</span>, <span>'password2'</span>)\n\n <span>def</span> <span>clean_email</span>(<span>self</span>):\n email = <span>self</span>.cleaned_data[<span>'email'</span>]\n <span>if</span> CustomUser.objects.filter(email=email).exists():\n <span>raise</span> forms.ValidationError(<span>'This email is already registered.'</span>)\n <span>return</span> email\n\n\n<span>class</span> <span>ProfileEditForm</span>(forms.ModelForm):\n <span>class</span> <span>Meta</span>:\n model = CustomUser\n fields = (<span>'first_name'</span>, <span>'last_name'</span>, <span>'email'</span>,\n <span>'phone'</span>, <span>'bio'</span>, <span>'avatar'</span>)</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/views.py</span>\n</div>\n<pre><span>import</span> secrets\n<span>from</span> django.shortcuts <span>import</span> render, redirect, get_object_or_404\n<span>from</span> django.contrib.auth <span>import</span> login\n<span>from</span> django.contrib.auth.decorators <span>import</span> login_required\n<span>from</span> django.core.mail <span>import</span> send_mail\n<span>from</span> django.conf <span>import</span> settings\n<span>from</span> .forms <span>import</span> SignupForm, ProfileEditForm\n<span>from</span> .models <span>import</span> CustomUser\n\n\n<span>def</span> <span>signup_view</span>(request):\n <span>if</span> request.method == <span>'POST'</span>:\n form = SignupForm(request.POST)\n <span>if</span> form.is_valid():\n user = form.save(commit=<span>False</span>)\n user.verify_token = secrets.token_urlsafe(<span>32</span>)\n user.save()\n <span>_send_verify_email</span>(request, user)\n login(request, user)\n <span>return</span> redirect(<span>'dashboard:index'</span>)\n <span>else</span>:\n form = SignupForm()\n <span>return</span> render(request, <span>'accounts/signup.html'</span>, {<span>'form'</span>: form})\n\n\n<span>def</span> <span>_send_verify_email</span>(request, user):\n token = user.verify_token\n link = request.build_absolute_uri(<span>f'/accounts/verify/{token}/'</span>)\n send_mail(\n subject=<span>'Verify your email'</span>,\n message=<span>f'Click to verify: {link}'</span>,\n from_email=settings.DEFAULT_FROM_EMAIL,\n recipient_list=[user.email],\n )\n\n\n<span>def</span> <span>verify_email_view</span>(request, token):\n user = get_object_or_404(CustomUser, verify_token=token)\n user.email_verified = <span>True</span>\n user.verify_token = <span>''</span>\n user.save(update_fields=[<span>'email_verified'</span>, <span>'verify_token'</span>])\n <span>return</span> redirect(<span>'dashboard:index'</span>)</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/urls.py</span>\n</div>\n<pre><span>from</span> django.urls <span>import</span> path\n<span>from</span> django.contrib.auth <span>import</span> views <span>as</span> auth_views\n<span>from</span> . <span>import</span> views\n\napp_name = <span>'accounts'</span>\n\nurlpatterns = [\n path(<span>'signup/'</span>, views.signup_view, name=<span>'signup'</span>),\n path(<span>'login/'</span>, auth_views.LoginView.as_view(\n template_name=<span>'accounts/login.html'</span>),\n name=<span>'login'</span>),\n path(<span>'logout/'</span>, auth_views.LogoutView.as_view(), name=<span>'logout'</span>),\n path(<span>'verify/&lt;str:token&gt;/'</span>, views.verify_email_view, name=<span>'verify'</span>),\n path(<span>'password-reset/'</span>, auth_views.PasswordResetView.as_view(\n template_name=<span>'accounts/password_reset.html'</span>),\n name=<span>'password_reset'</span>),\n path(<span>'password-reset/done/'</span>,\n auth_views.PasswordResetDoneView.as_view(\n template_name=<span>'accounts/password_reset_done.html'</span>),\n name=<span>'password_reset_done'</span>),\n path(<span>'reset/&lt;uidb64&gt;/&lt;token&gt;/'</span>,\n auth_views.PasswordResetConfirmView.as_view(\n template_name=<span>'accounts/password_reset_confirm.html'</span>),\n name=<span>'password_reset_confirm'</span>),\n path(<span>'reset/done/'</span>,\n auth_views.PasswordResetCompleteView.as_view(\n template_name=<span>'accounts/password_reset_complete.html'</span>),\n name=<span>'password_reset_complete'</span>),\n]</pre>\n</div>\n</section>\n<section class=\"step\" id=\"s11\">\n<div class=\"step-header\">\n<div class=\"step-badge\">11</div>\n<h2>Password reset flow</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django ships with a complete, cryptographically secure password-reset flow using signed tokens. You only need to wire up the templates and configure your email backend \u2014 no custom logic required.</div>\n<div class=\"step-body\">\n<p>Django's <code>PasswordResetView</code> through <code>PasswordResetCompleteView</code> is a four-step flow: request reset \u2192 confirm email sent \u2192 click link \u2192 choose new password \u2192 done. All four steps are registered in <code>accounts/urls.py</code> above.</p>\n<p>The only requirement is a working email backend in production. For development, the console backend prints the reset link to your terminal.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/dev.py \u2014 email to console</span>\n</div>\n<pre><span># Prints email to the terminal \u2014 no SMTP setup needed for dev</span>\nEMAIL_BACKEND = <span>'django.core.mail.backends.console.EmailBackend'</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/prod.py \u2014 real SMTP</span>\n</div>\n<pre>EMAIL_BACKEND = <span>'django.core.mail.backends.smtp.EmailBackend'</span>\nEMAIL_HOST = config(<span>'EMAIL_HOST'</span>)\nEMAIL_PORT = config(<span>'EMAIL_PORT'</span>, cast=int, default=<span>587</span>)\nEMAIL_USE_TLS = <span>True</span>\nEMAIL_HOST_USER = config(<span>'EMAIL_HOST_USER'</span>)\nEMAIL_HOST_PASSWORD = config(<span>'EMAIL_HOST_PASSWORD'</span>)</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> For production email use a transactional service like <strong>Mailgun</strong>, <strong>SendGrid</strong>, or <strong>Amazon SES</strong> rather than Gmail. Gmail throttles bulk sends and revokes app passwords arbitrarily.</div>\n</section>\n<section class=\"step\" id=\"s12\">\n<div class=\"step-header\">\n<div class=\"step-badge\">12</div>\n<h2>Email verification</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Email verification proves the user owns the address, reduces spam registrations, and is required by many mail providers before you're allowed to send bulk messages.</div>\n<div class=\"step-body\">\n<p>The <code>verify_token</code> field on <code>CustomUser</code> stores a 32-byte URL-safe token generated at signup. When the user clicks the verification link, Django finds the user by token, sets <code>email_verified = True</code>, and clears the token.</p>\n<p>Gate protected views with a simple check \u2014 either a decorator or a mixin \u2014 that redirects unverified users to a \"please verify your email\" page.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/decorators.py</span>\n</div>\n<pre><span>from</span> functools <span>import</span> wraps\n<span>from</span> django.shortcuts <span>import</span> redirect\n\n<span>def</span> <span>email_verified_required</span>(view_func):\n <span>@wraps</span>(view_func)\n <span>def</span> <span>wrapper</span>(request, *args, **kwargs):\n <span>if not</span> request.user.is_authenticated:\n <span>return</span> redirect(<span>'accounts:login'</span>)\n <span>if not</span> request.user.email_verified:\n <span>return</span> redirect(<span>'accounts:verify_pending'</span>)\n <span>return</span> view_func(request, *args, **kwargs)\n <span>return</span> wrapper</pre>\n</div>\n</section>\n<section class=\"step\" id=\"s13\">\n<div class=\"step-header\">\n<div class=\"step-badge\">13</div>\n<h2>Base template &amp; dashboard layout</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A shared <code>base.html</code> gives every screen the same sidebar, topbar, and notification area. Changing the nav once updates every page simultaneously.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/base.html</span>\n</div>\n<pre><span>&lt;!DOCTYPE html&gt;</span>\n<span>&lt;html</span> <span>lang</span>=<span>\"en\"</span><span>&gt;</span>\n<span>&lt;head&gt;</span>\n <span>&lt;meta</span> <span>charset</span>=<span>\"UTF-8\"</span><span>/&gt;</span>\n <span>&lt;meta</span> <span>name</span>=<span>\"viewport\"</span> <span>content</span>=<span>\"width=device-width, initial-scale=1\"</span><span>/&gt;</span>\n <span>&lt;title&gt;</span>{% block title %}UserMgmt{% endblock %}<span>&lt;/title&gt;</span>\n {% load static %}\n <span>&lt;link</span> <span>rel</span>=<span>\"stylesheet\"</span> <span>href</span>=<span>\"{% static 'css/dashboard.css' %}\"</span><span>/&gt;</span>\n <span>&lt;script</span> <span>src</span>=<span>\"https://cdn.jsdelivr.net/npm/chart.js\"</span> <span>defer</span><span>&gt;&lt;/script&gt;</span>\n<span>&lt;/head&gt;</span>\n<span>&lt;body&gt;</span>\n <span>&lt;div</span> <span>class</span>=<span>\"layout\"</span><span>&gt;</span>\n <span>&lt;aside</span> <span>class</span>=<span>\"sidebar\"</span><span>&gt;</span>\n {% include \"partials/sidebar.html\" %}\n <span>&lt;/aside&gt;</span>\n <span>&lt;div</span> <span>class</span>=<span>\"main\"</span><span>&gt;</span>\n {% include \"partials/topbar.html\" %}\n <span>&lt;main</span> <span>class</span>=<span>\"page-content\"</span><span>&gt;</span>\n {% if messages %}\n {% for msg in messages %}\n <span>&lt;div</span> <span>class</span>=<span>\"alert alert-{{ msg.tags }}\"</span><span>&gt;</span>{{ msg }}<span>&lt;/div&gt;</span>\n {% endfor %}\n {% endif %}\n {% block content %}{% endblock %}\n <span>&lt;/main&gt;</span>\n <span>&lt;/div&gt;</span>\n <span>&lt;/div&gt;</span>\n <span>&lt;script</span> <span>src</span>=<span>\"{% static 'js/dashboard.js' %}\"</span><span>&gt;&lt;/script&gt;</span>\n {% block extra_js %}{% endblock %}\n<span>&lt;/body&gt;</span>\n<span>&lt;/html&gt;</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">CSS</span>\n<span class=\"code-file\">static/css/dashboard.css (layout skeleton)</span>\n</div>\n<pre><span>/* \u2500\u2500 Layout \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n:root {\n --sidebar-w: 240px;\n --topbar-h: 56px;\n --bg: #0d1117;\n --surface: #161b22;\n --border: #2a3444;\n --text: #e6edf3;\n --muted: #8b949e;\n --accent: #3fb950; <span>/* green accent for user mgmt */</span>\n}\n*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\nbody { background: var(--bg); color: var(--text); font-family: 'Inter', sans-serif; }\n\n.layout { display: flex; min-height: 100vh; }\n.sidebar { width: var(--sidebar-w); background: var(--surface);\n border-right: 1px solid var(--border); position: fixed;\n top: 0; bottom: 0; overflow-y: auto; }\n.main { margin-left: var(--sidebar-w); flex: 1; display: flex; flex-direction: column; }\n.topbar { height: var(--topbar-h); background: var(--surface);\n border-bottom: 1px solid var(--border);\n display: flex; align-items: center; padding: 0 24px;\n position: sticky; top: 0; z-index: 50; }\n.page-content { padding: 32px 40px; }\n\n<span>/* \u2500\u2500 Cards \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.card { background: var(--surface); border: 1px solid var(--border);\n border-radius: 8px; padding: 20px; }\n\n<span>/* \u2500\u2500 User table \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.user-table { width: 100%; border-collapse: collapse; font-size: 13px; }\n.user-table th { background: #0d1117; color: var(--muted); text-align: left;\n font-family: monospace; font-size: 11px; letter-spacing: .04em;\n text-transform: uppercase; padding: 10px 14px;\n border-bottom: 1px solid var(--border); }\n.user-table td { padding: 11px 14px; border-bottom: 1px solid rgba(42,52,68,.5);\n vertical-align: middle; }\n.user-table tr:hover td { background: rgba(63,185,80,.04); }\n\n<span>/* \u2500\u2500 Badges \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.badge { display: inline-block; padding: 2px 9px; border-radius: 12px;\n font-size: 11px; font-family: monospace; font-weight: 600; }\n.badge-admin { background: rgba(124,158,255,.15); color: #7c9eff; }\n.badge-staff { background: rgba(63,185,80,.15); color: #3fb950; }\n.badge-viewer { background: rgba(139,148,158,.15); color: #8b949e; }\n.badge-active { background: rgba(63,185,80,.15); color: #3fb950; }\n.badge-inactive{ background: rgba(247,129,102,.15); color: #f78166; }\n\n<span>/* \u2500\u2500 Avatar \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.avatar { width: 32px; height: 32px; border-radius: 50%; object-fit: cover;\n border: 1.5px solid var(--border); }\n.avatar-initials { width: 32px; height: 32px; border-radius: 50%;\n background: rgba(63,185,80,.2); border: 1.5px solid rgba(63,185,80,.4);\n display: inline-flex; align-items: center; justify-content: center;\n font-family: monospace; font-size: 11px; font-weight: 600; color: #3fb950; }\n\n<span>/* \u2500\u2500 Buttons \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.btn { display: inline-flex; align-items: center; gap: 6px;\n padding: 7px 16px; border-radius: 6px; font-size: 13px;\n font-weight: 500; cursor: pointer; border: 1px solid transparent;\n text-decoration: none; transition: .15s; }\n.btn-primary { background: var(--accent); color: #0d1117; border-color: var(--accent); }\n.btn-primary:hover { filter: brightness(1.1); }\n.btn-secondary { background: transparent; color: var(--text); border-color: var(--border); }\n.btn-secondary:hover { border-color: var(--accent); color: var(--accent); }\n.btn-danger { background: transparent; color: #f78166; border-color: rgba(247,129,102,.4); }\n.btn-danger:hover { background: rgba(247,129,102,.1); }\n\n<span>/* \u2500\u2500 Form inputs \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.form-control { width: 100%; background: #0d1117; border: 1px solid var(--border);\n border-radius: 6px; color: var(--text); padding: 9px 12px;\n font-size: 14px; transition: border-color .15s; }\n.form-control:focus { outline: none; border-color: var(--accent); }\n.form-label { display: block; font-size: 12px; color: var(--muted);\n font-family: monospace; text-transform: uppercase;\n letter-spacing: .05em; margin-bottom: 6px; }</pre>\n</div>\n</section>\n<section class=\"step\" id=\"s14\">\n<div class=\"step-header\">\n<div class=\"step-badge\">14</div>\n<h2>User list &amp; search view</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A searchable, filterable user table is the central screen of any user management system. Getting pagination and filtering right now means the view stays fast even with tens of thousands of users.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">dashboard/views.py</span>\n</div>\n<pre><span>from</span> django.contrib.auth.decorators <span>import</span> login_required\n<span>from</span> django.core.paginator <span>import</span> Paginator\n<span>from</span> django.db.models <span>import</span> Q, Count\n<span>from</span> django.shortcuts <span>import</span> render, redirect, get_object_or_404\n<span>from</span> accounts.models <span>import</span> CustomUser\n\n\n<span>@login_required</span>\n<span>def</span> <span>user_list</span>(request):\n q = request.GET.get(<span>'q'</span>, <span>''</span>)\n role = request.GET.get(<span>'role'</span>, <span>''</span>)\n qs = CustomUser.objects.select_related().order_by(<span>'-date_joined'</span>)\n\n <span>if</span> q:\n qs = qs.filter(\n Q(email__icontains=q) |\n Q(username__icontains=q) |\n Q(first_name__icontains=q) |\n Q(last_name__icontains=q)\n )\n <span>if</span> role:\n qs = qs.filter(role_name=role)\n\n paginator = Paginator(qs, <span>20</span>)\n page = paginator.get_page(request.GET.get(<span>'page'</span>))\n <span>return</span> render(request, <span>'dashboard/user_list.html'</span>, {\n <span>'page_obj'</span>: page,\n <span>'total'</span>: qs.count(),\n <span>'q'</span>: q,\n <span>'role'</span>: role,\n })</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/dashboard/user_list.html</span>\n</div>\n<pre>{% extends \"base.html\" %}\n{% block title %}Users \u00b7 UserMgmt{% endblock %}\n{% block content %}\n<span>&lt;div</span> <span>class</span>=<span>\"page-header\"</span><span>&gt;</span>\n <span>&lt;h1&gt;</span>Users <span>&lt;span</span> <span>class</span>=<span>\"badge badge-staff\"</span><span>&gt;</span>{{ total }}<span>&lt;/span&gt;&lt;/h1&gt;</span>\n <span>&lt;a</span> <span>href</span>=<span>\"{% url 'dashboard:user_create' %}\"</span> <span>class</span>=<span>\"btn btn-primary\"</span><span>&gt;</span>+ Add user<span>&lt;/a&gt;</span>\n<span>&lt;/div&gt;</span>\n\n<span>&lt;form</span> <span>method</span>=<span>\"get\"</span> <span>class</span>=<span>\"filter-row\"</span><span>&gt;</span>\n <span>&lt;input</span> <span>class</span>=<span>\"form-control\"</span> <span>name</span>=<span>\"q\"</span> <span>placeholder</span>=<span>\"Search users\u2026\"</span>\n <span>value</span>=<span>\"{{ q }}\"</span><span>/&gt;</span>\n <span>&lt;select</span> <span>class</span>=<span>\"form-control\"</span> <span>name</span>=<span>\"role\"</span><span>&gt;</span>\n <span>&lt;option</span> <span>value</span>=<span>\"\"</span><span>&gt;</span>All roles<span>&lt;/option&gt;</span>\n <span>&lt;option</span> <span>value</span>=<span>\"admin\"</span> {% if role == \"admin\" %}selected{% endif %}<span>&gt;</span>Admin<span>&lt;/option&gt;</span>\n <span>&lt;option</span> <span>value</span>=<span>\"staff\"</span> {% if role == \"staff\" %}selected{% endif %}<span>&gt;</span>Staff<span>&lt;/option&gt;</span>\n <span>&lt;option</span> <span>value</span>=<span>\"viewer\"</span> {% if role == \"viewer\" %}selected{% endif %}<span>&gt;</span>Viewer<span>&lt;/option&gt;</span>\n <span>&lt;/select&gt;</span>\n <span>&lt;button</span> <span>class</span>=<span>\"btn btn-secondary\"</span><span>&gt;</span>Filter<span>&lt;/button&gt;</span>\n<span>&lt;/form&gt;</span>\n\n<span>&lt;div</span> <span>class</span>=<span>\"card\"</span> <span>style</span>=<span>\"padding:0;overflow:hidden;margin-top:20px\"</span><span>&gt;</span>\n<span>&lt;table</span> <span>class</span>=<span>\"user-table\"</span><span>&gt;</span>\n <span>&lt;thead&gt;&lt;tr&gt;</span>\n <span>&lt;th&gt;</span>User<span>&lt;/th&gt;&lt;th&gt;</span>Role<span>&lt;/th&gt;&lt;th&gt;</span>Status<span>&lt;/th&gt;</span>\n <span>&lt;th&gt;</span>Joined<span>&lt;/th&gt;&lt;th&gt;</span>Actions<span>&lt;/th&gt;</span>\n <span>&lt;/tr&gt;&lt;/thead&gt;</span>\n <span>&lt;tbody&gt;</span>\n {% for u in page_obj %}\n <span>&lt;tr&gt;</span>\n <span>&lt;td&gt;</span>\n {% if u.avatar %}\n <span>&lt;img</span> <span>src</span>=<span>\"{{ u.avatar.url }}\"</span> <span>class</span>=<span>\"avatar\"</span><span>/&gt;</span>\n {% else %}\n <span>&lt;span</span> <span>class</span>=<span>\"avatar-initials\"</span><span>&gt;</span>{{ u.first_name.0 }}{{ u.last_name.0 }}<span>&lt;/span&gt;</span>\n {% endif %}\n <span>&lt;strong&gt;</span>{{ u.get_full_name|default:u.username }}<span>&lt;/strong&gt;</span>\n <span>&lt;div</span> <span>style</span>=<span>\"color:#8b949e;font-size:12px\"</span><span>&gt;</span>{{ u.email }}<span>&lt;/div&gt;</span>\n <span>&lt;/td&gt;</span>\n <span>&lt;td&gt;&lt;span</span> <span>class</span>=<span>\"badge badge-{{ u.role_name }}\"</span><span>&gt;</span>{{ u.role_name }}<span>&lt;/span&gt;&lt;/td&gt;</span>\n <span>&lt;td&gt;&lt;span</span> <span>class</span>=<span>\"badge {% if u.is_active %}badge-active{% else %}badge-inactive{% endif %}\"</span><span>&gt;</span>\n {% if u.is_active %}Active{% else %}Inactive{% endif %}\n <span>&lt;/span&gt;&lt;/td&gt;</span>\n <span>&lt;td&gt;</span>{{ u.date_joined|date:\"Y-m-d\" }}<span>&lt;/td&gt;</span>\n <span>&lt;td&gt;</span>\n <span>&lt;a</span> <span>href</span>=<span>\"{% url 'dashboard:user_edit' u.pk %}\"</span> <span>class</span>=<span>\"btn btn-secondary\"</span><span>&gt;</span>Edit<span>&lt;/a&gt;</span>\n <span>&lt;/td&gt;</span>\n <span>&lt;/tr&gt;</span>\n {% endfor %}\n <span>&lt;/tbody&gt;</span>\n<span>&lt;/table&gt;</span>\n<span>&lt;/div&gt;</span>\n\n{% include \"partials/pagination.html\" with page_obj=page_obj %}\n{% endblock %}</pre>\n</div>\n</section>\n<section class=\"step\" id=\"s15\">\n<div class=\"step-header\">\n<div class=\"step-badge\">15</div>\n<h2>Analytics dashboard with charts</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Aggregating registration trends and role breakdowns gives admins at-a-glance insight into user growth. Chart.js renders client-side with no server-side image generation.</div>\n<!-- Visual preview of the chart dashboard -->\n<div>\n<div>\n<div>\n<div>New Registrations \u2014 Last 7 days</div>\n<div>\n<div>\n<div class=\"bar\"></div>\n<div class=\"bar-label\">Mon</div>\n</div>\n<div>\n<div class=\"bar\"></div>\n<div class=\"bar-label\">Tue</div>\n</div>\n<div>\n<div class=\"bar\"></div>\n<div class=\"bar-label\">Wed</div>\n</div>\n<div>\n<div class=\"bar\"></div>\n<div class=\"bar-label\">Thu</div>\n</div>\n<div>\n<div class=\"bar\"></div>\n<div class=\"bar-label\">Fri</div>\n</div>\n<div>\n<div class=\"bar\"></div>\n<div class=\"bar-label\">Sat</div>\n</div>\n<div>\n<div class=\"bar\"></div>\n<div class=\"bar-label\">Sun</div>\n</div>\n</div>\n</div>\n<div>\n<div>Role distribution</div>\n<div>\n<div>\n\n<div>Admin</div>\n\n<div>10%</div>\n</div>\n<div>\n\n<div>Staff</div>\n\n<div>30%</div>\n</div>\n<div>\n\n<div>Viewer</div>\n\n<div>60%</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">dashboard/views.py \u2014 analytics view</span>\n</div>\n<pre><span>from</span> django.db.models.functions <span>import</span> TruncDate\n<span>from</span> django.utils <span>import</span> timezone\n<span>import</span> datetime, json\n\n<span>@login_required</span>\n<span>def</span> <span>analytics</span>(request):\n today = timezone.now().date()\n week_ago = today - datetime.timedelta(days=<span>6</span>)\n\n <span># Registrations per day for last 7 days</span>\n daily = (\n CustomUser.objects\n .filter(date_joined__date__gte=week_ago)\n .annotate(day=TruncDate(<span>'date_joined'</span>))\n .values(<span>'day'</span>)\n .annotate(count=Count(<span>'id'</span>))\n .order_by(<span>'day'</span>)\n )\n labels = [(week_ago + datetime.timedelta(i)).strftime(<span>'%a'</span>) <span>for</span> i <span>in</span> range(<span>7</span>)]\n day_map = {d[<span>'day'</span>].strftime(<span>'%a'</span>): d[<span>'count'</span>] <span>for</span> d <span>in</span> daily}\n counts = [day_map.get(l, <span>0</span>) <span>for</span> l <span>in</span> labels]\n\n <span># Role breakdown</span>\n role_counts = (\n CustomUser.objects.values(<span>'role_name'</span>)\n .annotate(count=Count(<span>'id'</span>))\n )\n\n <span>return</span> render(request, <span>'dashboard/analytics.html'</span>, {\n <span>'chart_labels'</span>: json.dumps(labels),\n <span>'chart_counts'</span>: json.dumps(counts),\n <span>'role_counts'</span>: list(role_counts),\n <span>'total_users'</span>: CustomUser.objects.count(),\n <span>'active_users'</span>: CustomUser.objects.filter(is_active=<span>True</span>).count(),\n <span>'verified_users'</span>: CustomUser.objects.filter(email_verified=<span>True</span>).count(),\n })</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/dashboard/analytics.html (chart section)</span>\n</div>\n<pre>{% block extra_js %}\n<span>&lt;script&gt;</span>\n <span>// Bar chart: daily registrations</span>\n <span>const</span> ctx1 = document.getElementById(<span>'regChart'</span>).getContext(<span>'2d'</span>);\n <span>new</span> Chart(ctx1, {\n type: <span>'bar'</span>,\n data: {\n labels: {{ chart_labels|safe }},\n datasets: [{ label: <span>'New users'</span>,\n data: {{ chart_counts|safe }},\n backgroundColor: <span>'rgba(63,185,80,.3)'</span>,\n borderColor: <span>'#3fb950'</span>,\n borderWidth: 1, borderRadius: 4 }]\n },\n options: {\n plugins: { legend: { display: <span>false</span> } },\n scales: { x: { grid: { color: <span>'rgba(42,52,68,.5)'</span> },\n ticks: { color: <span>'#8b949e'</span> } },\n y: { grid: { color: <span>'rgba(42,52,68,.5)'</span> },\n ticks: { color: <span>'#8b949e'</span>, precision: 0 } } }\n }\n });\n\n <span>// Doughnut chart: role breakdown</span>\n <span>const</span> ctx2 = document.getElementById(<span>'roleChart'</span>).getContext(<span>'2d'</span>);\n <span>new</span> Chart(ctx2, {\n type: <span>'doughnut'</span>,\n data: {\n labels: [<span>'Admin'</span>, <span>'Staff'</span>, <span>'Viewer'</span>],\n datasets: [{ data: [{% for r in role_counts %}{{ r.count }},{% endfor %}],\n backgroundColor: [<span>'#7c9eff'</span>, <span>'#3fb950'</span>, <span>'#8b949e'</span>],\n borderWidth: 0 }]\n },\n options: { plugins: { legend: { labels: { color: <span>'#c9d1d9'</span> } } },\n cutout: <span>'68%'</span> }\n });\n<span>&lt;/script&gt;</span>\n{% endblock %}</pre>\n</div>\n</section>\n<section class=\"step\" id=\"s16\">\n<div class=\"step-header\">\n<div class=\"step-badge\">16</div>\n<h2>Profile &amp; edit views</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Users need to update their own profile. Admins need to edit any user's role and status. These are two different views with different permission requirements.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">dashboard/views.py \u2014 profile &amp; edit</span>\n</div>\n<pre><span>@login_required</span>\n<span>def</span> <span>profile_view</span>(request):\n <span>if</span> request.method == <span>'POST'</span>:\n form = ProfileEditForm(request.POST, request.FILES, instance=request.user)\n <span>if</span> form.is_valid():\n form.save()\n messages.success(request, <span>'Profile updated.'</span>)\n <span>return</span> redirect(<span>'dashboard:profile'</span>)\n <span>else</span>:\n form = ProfileEditForm(instance=request.user)\n <span>return</span> render(request, <span>'dashboard/profile.html'</span>, {<span>'form'</span>: form})\n\n\n<span>@login_required</span>\n<span>def</span> <span>user_edit</span>(request, pk):\n <span>if not</span> request.user.is_admin_user:\n <span>return</span> redirect(<span>'dashboard:index'</span>)\n target = get_object_or_404(CustomUser, pk=pk)\n <span>if</span> request.method == <span>'POST'</span>:\n form = AdminUserEditForm(request.POST, request.FILES, instance=target)\n <span>if</span> form.is_valid():\n form.save()\n ActivityLog.objects.create(\n user=request.user,\n action=<span>f'Edited user {target.email}'</span>,\n ip_address=request.META.get(<span>'REMOTE_ADDR'</span>),\n )\n messages.success(request, <span>'User updated.'</span>)\n <span>return</span> redirect(<span>'dashboard:user_list'</span>)\n <span>else</span>:\n form = AdminUserEditForm(instance=target)\n <span>return</span> render(request, <span>'dashboard/user_edit.html'</span>,\n {<span>'form'</span>: form, <span>'target'</span>: target})</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/forms.py \u2014 AdminUserEditForm</span>\n</div>\n<pre><span>class</span> <span>AdminUserEditForm</span>(forms.ModelForm):\n <span>class</span> <span>Meta</span>:\n model = CustomUser\n fields = (<span>'first_name'</span>, <span>'last_name'</span>, <span>'email'</span>,\n <span>'role_name'</span>, <span>'is_active'</span>, <span>'phone'</span>, <span>'bio'</span>)</pre>\n</div>\n</section>\n<section class=\"step\" id=\"s17\">\n<div class=\"step-header\">\n<div class=\"step-badge\">17</div>\n<h2>Roles &amp; permissions in templates</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Hiding edit buttons from viewers is cosmetic. What actually protects data is checking roles in the view. But template guards make the UI consistent and prevent confusion.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">in any template</span>\n</div>\n<pre><span>&lt;!-- Show \"Edit\" only to admin and staff --&gt;</span>\n{% if user.is_staff_user %}\n <span>&lt;a</span> <span>href</span>=<span>\"{% url 'dashboard:user_edit' u.pk %}\"</span>\n <span>class</span>=<span>\"btn btn-secondary\"</span><span>&gt;</span>Edit<span>&lt;/a&gt;</span>\n{% endif %}\n\n<span>&lt;!-- Show \"Delete\" only to admin --&gt;</span>\n{% if user.is_admin_user %}\n <span>&lt;form</span> <span>method</span>=<span>\"post\"</span> <span>action</span>=<span>\"{% url 'dashboard:user_delete' u.pk %}\"</span><span>&gt;</span>\n {% csrf_token %}\n <span>&lt;button</span> <span>class</span>=<span>\"btn btn-danger\"</span><span>&gt;</span>Delete<span>&lt;/button&gt;</span>\n <span>&lt;/form&gt;</span>\n{% endif %}</pre>\n</div>\n<div class=\"tone-danger\"><strong>Never rely on template guards alone.</strong> Always check <code>request.user.is_admin_user</code> (or the equivalent) at the top of any view that modifies data. A user can manually POST to any URL they guess.</div>\n</section>\n<section class=\"step\" id=\"s18\">\n<div class=\"step-header\">\n<div class=\"step-badge\">18</div>\n<h2>Decorators &amp; mixins for access control</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Repeating role checks inline in every view is fragile. Centralizing them in a decorator or mixin means you change the rule in one place and it propagates everywhere.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/decorators.py</span>\n</div>\n<pre><span>from</span> functools <span>import</span> wraps\n<span>from</span> django.shortcuts <span>import</span> redirect\n<span>from</span> django.contrib <span>import</span> messages\n\n<span>def</span> <span>admin_required</span>(view_func):\n <span>@wraps</span>(view_func)\n <span>def</span> <span>wrapper</span>(request, *args, **kwargs):\n <span>if not</span> request.user.is_authenticated:\n <span>return</span> redirect(<span>'accounts:login'</span>)\n <span>if not</span> request.user.is_admin_user:\n messages.error(request, <span>'You do not have permission to do that.'</span>)\n <span>return</span> redirect(<span>'dashboard:index'</span>)\n <span>return</span> view_func(request, *args, **kwargs)\n <span>return</span> wrapper\n\n<span>def</span> <span>staff_required</span>(view_func):\n <span>@wraps</span>(view_func)\n <span>def</span> <span>wrapper</span>(request, *args, **kwargs):\n <span>if not</span> request.user.is_authenticated:\n <span>return</span> redirect(<span>'accounts:login'</span>)\n <span>if not</span> request.user.is_staff_user:\n messages.error(request, <span>'Staff or admin access required.'</span>)\n <span>return</span> redirect(<span>'dashboard:index'</span>)\n <span>return</span> view_func(request, *args, **kwargs)\n <span>return</span> wrapper</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">dashboard/views.py \u2014 usage</span>\n</div>\n<pre><span>from</span> accounts.decorators <span>import</span> admin_required, staff_required\n\n<span>@admin_required</span>\n<span>def</span> <span>user_delete</span>(request, pk):\n user = get_object_or_404(CustomUser, pk=pk)\n <span>if</span> request.method == <span>'POST'</span>:\n user.is_active = <span>False</span> <span># soft-delete: deactivate, don't destroy</span>\n user.save(update_fields=[<span>'is_active'</span>])\n messages.success(request, <span>f'{user.email} has been deactivated.'</span>)\n <span>return</span> redirect(<span>'dashboard:user_list'</span>)</pre>\n</div>\n<div>Prefer soft-deletes (<code>is_active = False</code>) over actually removing users from the database. It preserves foreign-key integrity, audit trails, and lets you re-activate accounts.</div>\n</section>\n<section class=\"step\" id=\"s19\">\n<div class=\"step-header\">\n<div class=\"step-badge\">19</div>\n<h2>Activity log</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>An activity log answers \"who changed what and when\" \u2014 essential for debugging, compliance, and support. Writing a log entry is one line; reading it when something goes wrong is invaluable.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">accounts/utils.py</span>\n</div>\n<pre><span>from</span> .models <span>import</span> ActivityLog\n\n<span>def</span> <span>log_action</span>(user, action, request=<span>None</span>):\n ip = <span>None</span>\n <span>if</span> request:\n xff = request.META.get(<span>'HTTP_X_FORWARDED_FOR'</span>)\n ip = xff.split(<span>','</span>)[<span>0</span>].strip() <span>if</span> xff <span>else</span> \\\n request.META.get(<span>'REMOTE_ADDR'</span>)\n ActivityLog.objects.create(user=user, action=action, ip_address=ip)</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">dashboard/views.py \u2014 activity log view</span>\n</div>\n<pre><span>@staff_required</span>\n<span>def</span> <span>activity_log</span>(request):\n logs = ActivityLog.objects.select_related(<span>'user'</span>).order_by(<span>'-created_at'</span>)[:<span>200</span>]\n <span>return</span> render(request, <span>'dashboard/activity_log.html'</span>, {<span>'logs'</span>: logs})</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">dashboard/urls.py</span>\n</div>\n<pre><span>from</span> django.urls <span>import</span> path\n<span>from</span> . <span>import</span> views\n\napp_name = <span>'dashboard'</span>\n\nurlpatterns = [\n path(<span>''</span>, views.index, name=<span>'index'</span>),\n path(<span>'users/'</span>, views.user_list, name=<span>'user_list'</span>),\n path(<span>'users/create/'</span>, views.user_create, name=<span>'user_create'</span>),\n path(<span>'users/&lt;int:pk&gt;/edit/'</span>, views.user_edit, name=<span>'user_edit'</span>),\n path(<span>'users/&lt;int:pk&gt;/delete/'</span>,views.user_delete, name=<span>'user_delete'</span>),\n path(<span>'analytics/'</span>, views.analytics, name=<span>'analytics'</span>),\n path(<span>'profile/'</span>, views.profile_view, name=<span>'profile'</span>),\n path(<span>'activity/'</span>, views.activity_log, name=<span>'activity_log'</span>),\n]</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/urls.py</span>\n</div>\n<pre><span>from</span> django.contrib <span>import</span> admin\n<span>from</span> django.urls <span>import</span> path, include\n<span>from</span> django.conf <span>import</span> settings\n<span>from</span> django.conf.urls.static <span>import</span> static\n\nurlpatterns = [\n path(<span>'admin/'</span>, admin.site.urls),\n path(<span>'accounts/'</span>, include(<span>'accounts.urls'</span>)),\n path(<span>'dashboard/'</span>, include(<span>'dashboard.urls'</span>)),\n] + static(settings.MEDIA_URL, document_root=settings.MEDIA_ROOT)</pre>\n</div>\n</section>\n<section class=\"step\" id=\"s20\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">20</div>\n<h2>Production settings</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Production settings are meaningfully different from dev: <code>DEBUG</code> is off, PostgreSQL replaces SQLite, HTTPS is enforced, and static files are served through WhiteNoise. Separating them in <code>prod.py</code> makes this explicit.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/prod.py</span>\n</div>\n<pre><span>from</span> .base <span>import</span> *\n<span>from</span> decouple <span>import</span> config\n<span>import</span> dj_database_url\n\nDEBUG = <span>False</span>\nALLOWED_HOSTS = config(<span>'ALLOWED_HOSTS'</span>, cast=<span>lambda</span> v: [s.strip() <span>for</span> s <span>in</span> v.split(<span>','</span>)])\n\nDATABASES = {<span>'default'</span>: dj_database_url.config(\n default=config(<span>'DATABASE_URL'</span>), conn_max_age=<span>600</span>)}\n\nMIDDLEWARE = [\n <span>'django.middleware.security.SecurityMiddleware'</span>,\n <span>'whitenoise.middleware.WhiteNoiseMiddleware'</span>,\n] + MIDDLEWARE[<span>1</span>:]\n\nSTATICFILES_STORAGE = <span>'whitenoise.storage.CompressedManifestStaticFilesStorage'</span>\n\nSECURE_SSL_REDIRECT = <span>True</span>\nSESSION_COOKIE_SECURE = <span>True</span>\nCSRF_COOKIE_SECURE = <span>True</span>\nSECURE_HSTS_SECONDS = <span>31536000</span>\nSECURE_HSTS_INCLUDE_SUBDOMAINS = <span>True</span>\nX_FRAME_OPTIONS = <span>'DENY'</span>\n\n<span># Real SMTP</span>\nEMAIL_BACKEND = <span>'django.core.mail.backends.smtp.EmailBackend'</span>\nEMAIL_HOST = config(<span>'EMAIL_HOST'</span>)\nEMAIL_PORT = config(<span>'EMAIL_PORT'</span>, cast=int, default=<span>587</span>)\nEMAIL_USE_TLS = <span>True</span>\nEMAIL_HOST_USER = config(<span>'EMAIL_HOST_USER'</span>)\nEMAIL_HOST_PASSWORD = config(<span>'EMAIL_HOST_PASSWORD'</span>)</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install dj-database-url\npip freeze &gt; requirements.txt</pre>\n</div>\n</section>\n<section class=\"step\" id=\"s21\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">21</div>\n<h2>Gunicorn &amp; WhiteNoise</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django's <code>runserver</code> is single-threaded and explicitly not safe for production. Gunicorn handles concurrent requests; WhiteNoise serves static files efficiently without a separate web server.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal \u2014 local production test</span>\n</div>\n<pre>DJANGO_SETTINGS_MODULE=core.settings.prod \\\npython manage.py collectstatic --noinput\n\nDJANGO_SETTINGS_MODULE=core.settings.prod \\\ngunicorn core.wsgi:application \\\n --bind 0.0.0.0:8000 \\\n --workers 3 \\\n --timeout 30</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">Procfile (Railway / Render / Heroku)</span>\n</div>\n<pre>web: gunicorn core.wsgi:application --workers 3 --timeout 30\nrelease: python manage.py migrate</pre>\n</div>\n<div>Set <code>WEB_CONCURRENCY=3</code> as an environment variable on the platform instead of hardcoding <code>--workers</code> in the Procfile. Most platforms read this variable automatically.</div>\n</section>\n<section class=\"step\" id=\"s22\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">22</div>\n<h2>Deploy to Railway or Render</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Both Railway and Render offer free-tier PostgreSQL add-ons, automatic deploys from GitHub, and managed HTTPS \u2014 everything you need for a production user management system at zero cost to start.</div>\n<div class=\"step-body\">\n<p><strong>Railway</strong> detects a <code>Procfile</code> and a Python project automatically. Push your code, add a PostgreSQL plugin, and set environment variables.</p>\n<p><strong>Render</strong> requires a <code>render.yaml</code> blueprint file for reproducible deploys.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>git init &amp;&amp; git add -A &amp;&amp; git commit -m \"initial\"\ngh repo create usermgmt --public --push <span># GitHub CLI</span>\n\n<span># Then on Railway: New Project \u2192 Deploy from GitHub \u2192 select repo</span>\n<span># Add PostgreSQL plugin \u2192 copy DATABASE_URL into Variables tab</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">YAML</span>\n<span class=\"code-file\">render.yaml</span>\n</div>\n<pre>services:\n - type: web\n name: usermgmt\n runtime: python\n buildCommand: pip install -r requirements.txt &amp;&amp; python manage.py collectstatic --noinput\n startCommand: gunicorn core.wsgi:application --workers 3\n envVars:\n - key: DJANGO_SETTINGS_MODULE\n value: core.settings.prod\n - key: SECRET_KEY\n generateValue: true\n - key: DATABASE_URL\n fromDatabase:\n name: usermgmt-db\n property: connectionString\n\ndatabases:\n - name: usermgmt-db\n plan: free</pre>\n</div>\n<div class=\"table-wrap\">\n<table>\n<tr><th>Platform</th><th>Free Postgres</th><th>Auto-deploy</th><th>Custom domain</th><th>Sleep on idle</th></tr>\n<tr><td>Railway</td><td>500 MB</td><td></td><td></td><td>No (Hobby+)</td></tr>\n<tr><td>Render</td><td>1 GB (90 days)</td><td></td><td></td><td>Yes (free tier)</td></tr>\n<tr><td>Fly.io</td><td>1 GB</td><td>manual</td><td></td><td>No</td></tr>\n</table>\n</div>\n</section>\n<section class=\"step\" id=\"s23\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">23</div>\n<h2>Pre-launch checklist</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>The most common production incidents come from shipping with dev settings, no email backend, or SQLite in prod. This checklist catches all of them in five minutes.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>DJANGO_SETTINGS_MODULE=core.settings.prod python manage.py check --deploy\npython manage.py migrate\npython manage.py collectstatic --noinput</pre>\n</div>\n<div class=\"checklist\">\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>DEBUG = False</strong> in <code>core/settings/prod.py</code> \u2014 a stack trace leaking to the public is a real vulnerability.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>SECRET_KEY</strong> is long, random, and lives only in environment variables \u2014 never in source control.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>ALLOWED_HOSTS</strong> lists only your real domain(s), not <code>\"*\"</code>.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>HTTPS enforced</strong> via <code>SECURE_SSL_REDIRECT = True</code> and HSTS headers set.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>DATABASE_URL</strong> points at PostgreSQL, not the SQLite dev file.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>Email backend</strong> is SMTP, not the console backend. Send a test password reset email.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>STATIC_ROOT</strong> populated \u2014 <code>collectstatic</code> has been run on this exact deploy.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>MEDIA_ROOT</strong> is writable and not inside the static directory \u2014 avatars upload correctly.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>Custom user model</strong> set as <code>AUTH_USER_MODEL</code> before the first migration \u2014 confirm in <code>base.py</code>.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>Error tracking</strong> (Sentry or similar) configured so production exceptions don't vanish silently.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>Database backups enabled</strong> on the managed Postgres add-on \u2014 turn this on before you have real user data.</span></div>\n<div class=\"check-row\"><span class=\"check-box\"></span><span><strong>Soft-delete</strong> pattern used \u2014 deactivating users rather than deleting preserves audit logs and FK integrity.</span></div>\n</div>\n</section>\n<section id=\"cheatsheet\">\n<h2>User Management Cheat Sheet</h2>\n<p class=\"section-sub\">Quick-reference commands, model patterns, permission shortcuts, and Chart.js integration tips.</p>\n<div class=\"cheat-grid\">\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span>\u2328</span><h3>Management Commands</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>makemigrations accounts</code><span>Generate migrations for CustomUser changes</span></div>\n<div class=\"cheat-item\"><code>migrate</code><span>Apply pending migrations to the database</span></div>\n<div class=\"cheat-item\"><code>createsuperuser</code><span>Create an admin account interactively</span></div>\n<div class=\"cheat-item\"><code>collectstatic --noinput</code><span>Gather all static files into STATIC_ROOT</span></div>\n<div class=\"cheat-item\"><code>check --deploy</code><span>Run security checks for production config</span></div>\n<div class=\"cheat-item\"><code>shell_plus</code><span>Auto-import all models (django-extensions)</span></div>\n<div class=\"cheat-item\"><code>sendtestemail you@x.com</code><span>Confirm email backend is working</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Custom User Patterns</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>AUTH_USER_MODEL</code><span>Must be set in base.py <em>before</em> first migrate</span></div>\n<div class=\"cheat-item\"><code>AbstractUser</code><span>Extend, not replace \u2014 keeps password hashing, sessions</span></div>\n<div class=\"cheat-item\"><code>update_fields=[...]</code><span>Partial save \u2014 only write changed columns</span></div>\n<div class=\"cheat-item\"><code>is_active = False</code><span>Soft-delete \u2014 disables login without losing FK refs</span></div>\n<div class=\"cheat-item\"><code>secrets.token_urlsafe(32)</code><span>Cryptographically safe email verify token</span></div>\n<div class=\"cheat-item\"><code>select_related('role')</code><span>Avoid N+1 queries on user list with FK role</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Permission Shortcuts</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>@login_required</code><span>Redirect unauthenticated users to LOGIN_URL</span></div>\n<div class=\"cheat-item\"><code>@admin_required</code><span>Custom decorator \u2014 admin role only</span></div>\n<div class=\"cheat-item\"><code>@staff_required</code><span>Custom decorator \u2014 staff + admin</span></div>\n<div class=\"cheat-item\"><code>@email_verified_required</code><span>Block unverified accounts from protected views</span></div>\n<div class=\"cheat-item\"><code>user.is_admin_user</code><span>Property on CustomUser \u2014 use in views &amp; templates</span></div>\n<div class=\"cheat-item\"><code>{% if user.is_staff_user %}</code><span>Template guard for edit/delete UI elements</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Chart.js Recipes</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>type: 'bar'</code><span>Daily registrations bar chart</span></div>\n<div class=\"cheat-item\"><code>type: 'doughnut'</code><span>Role distribution pie/donut</span></div>\n<div class=\"cheat-item\"><code>type: 'line'</code><span>Cumulative user growth over time</span></div>\n<div class=\"cheat-item\"><code>TruncDate</code><span>Django ORM \u2014 group by calendar day</span></div>\n<div class=\"cheat-item\"><code>json.dumps(list)</code><span>Pass Python list to template as JS array</span></div>\n<div class=\"cheat-item\"><code>{{ data|safe }}</code><span>Render JSON in template without escaping</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Email &amp; Verification</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>console.EmailBackend</code><span>Dev \u2014 prints emails to terminal, no SMTP setup</span></div>\n<div class=\"cheat-item\"><code>smtp.EmailBackend</code><span>Production \u2014 set HOST, PORT, USER, PASSWORD in env</span></div>\n<div class=\"cheat-item\"><code>send_mail()</code><span>Simple one-shot email send</span></div>\n<div class=\"cheat-item\"><code>PasswordResetView</code><span>Django built-in \u2014 just add templates + URL</span></div>\n<div class=\"cheat-item\"><code>build_absolute_uri(path)</code><span>Generate full verify URL including domain</span></div>\n<div class=\"cheat-item\"><code>email_verified = True</code><span>Set after token confirmed; clear verify_token field</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Security Settings</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>SECURE_SSL_REDIRECT</code><span>Force all HTTP to HTTPS in production</span></div>\n<div class=\"cheat-item\"><code>SESSION_COOKIE_SECURE</code><span>Only send session cookie over HTTPS</span></div>\n<div class=\"cheat-item\"><code>CSRF_COOKIE_SECURE</code><span>Only send CSRF cookie over HTTPS</span></div>\n<div class=\"cheat-item\"><code>SECURE_HSTS_SECONDS</code><span>HSTS header (31536000 = 1 year)</span></div>\n<div class=\"cheat-item\"><code>X_FRAME_OPTIONS</code><span>Set \"DENY\" to block clickjacking iframes</span></div>\n<div class=\"cheat-item\"><code>check --deploy</code><span>Django's built-in security audit \u2014 run before launch</span></div>\n</div>\n</div>\n</div>\n</section>";

